// Merge Request with Context
// Handles clear_all_filters and clear_*_filters flags

const webhook = $('Property Search Webhook').first().json.body || {};
const savedContext = $input.first().json || {};
const clearAll = webhook.clear_all_filters === true;

const merged = {
  CLIENT_ID: webhook.CLIENT_ID || '',
  session_id: webhook.session_id || '',

  // Core search parameters - DON'T use saved context if clear_all_filters
  location_name: clearAll ? '' : (webhook.location_name || savedContext.location_name || ''),
  property_type: clearAll ? '' : (webhook.property_type || savedContext.property_type || ''),

  // Price filters
  list_price_min: (clearAll || webhook.clear_price_filters)
    ? (parseInt(webhook.list_price_min) || 0)
    : (parseInt(webhook.list_price_min) || parseInt(savedContext.list_price_min) || 0),

  list_price_max: (clearAll || webhook.clear_price_filters)
    ? (parseInt(webhook.list_price_max) || 0)
    : (parseInt(webhook.list_price_max) || parseInt(savedContext.list_price_max) || 0),

  // Bedroom filters
  bedrooms_min: (clearAll || webhook.clear_bedroom_filters)
    ? (parseInt(webhook.bedrooms_min) || 0)
    : (parseInt(webhook.bedrooms_min) || parseInt(savedContext.bedrooms_min) || 0),

  bedrooms_max: (clearAll || webhook.clear_bedroom_filters)
    ? (parseInt(webhook.bedrooms_max) || 0)
    : (parseInt(webhook.bedrooms_max) || parseInt(savedContext.bedrooms_max) || 0),

  // Bathroom filters
  bathrooms_min: (clearAll || webhook.clear_bathroom_filters)
    ? (parseInt(webhook.bathrooms_min) || 0)
    : (parseInt(webhook.bathrooms_min) || parseInt(savedContext.bathrooms_min) || 0),

  bathrooms_max: (clearAll || webhook.clear_bathroom_filters)
    ? (parseInt(webhook.bathrooms_max) || 0)
    : (parseInt(webhook.bathrooms_max) || parseInt(savedContext.bathrooms_max) || 0),

  // Features
  features: clearAll ? '' : (webhook.features || savedContext.features || ''),

  // Pagination
  page: parseInt(webhook.page) || 1,
  limit: parseInt(webhook.limit) || parseInt(savedContext.limit) || 20,

  // Other parameters
  language: webhook.language || 'en_US',
  ref_no: webhook.ref_no || '',
  listing_type: webhook.listing_type || '',
  order: webhook.order || 'last_date_desc',

  // Size parameters
  build_size_min: parseInt(webhook.build_size_min) || 0,
  build_size_max: parseInt(webhook.build_size_max) || 0,
  plot_size_min: parseInt(webhook.plot_size_min) || 0,
  plot_size_max: parseInt(webhook.plot_size_max) || 0,

  // Property URL - client-specific detail page
  PROP_DETAIL_URL: webhook.PROP_DETAIL_URL || '',

  // Reset flag
  clear_all_filters: clearAll ? 'true' : 'false'
};

return { json: merged };

// ============================================
// VALIDATE & LOOKUP IDs
// Supports pre_parsed data, multi-location, ref_no, and reset
// ============================================

const mergedData = $('Merge Request with Context').first().json;
const webhookData = $('Property Search Webhook').first().json.body || {};
const mapsData = $input.first()?.json || {};

// ============================================
// CHECK FOR RESET SESSION REQUEST
// ============================================

if (webhookData.reset_session === true) {
  const sessionId = webhookData.session_id || mergedData.session_id || '';
  return {
    json: {
      skip_search: true,
      reset_session: true,
      session_id: sessionId,
      result: 'Session reset successfully'
    }
  };
}

// ============================================
// CHECK FOR REFERENCE NUMBER SEARCH
// If ref_no provided, skip location/type validation
// ============================================

const refNo = webhookData.ref_no || mergedData.ref_no || '';
if (refNo && refNo.trim() !== '') {
  // Reference number search - no location/type needed
  return {
    json: {
      skip_search: false,
      ref_no: refNo.trim(),
      location_id: null,
      type_id: null,
      search_mode: 'ref_no'
    }
  };
}

// ============================================
// CHECK FOR MULTI-LOCATION SEARCH (always check this first)
// ============================================

const location_ids_from_webhook = webhookData.location_ids || [];
const search_mode_from_webhook = webhookData.search_mode || 'single';

if (search_mode_from_webhook === 'multi' && location_ids_from_webhook.length > 1) {
  // Multi-location search - use IDs from ChatBot directly
  return {
    json: {
      skip_search: false,
      location_id: null,
      location_ids: location_ids_from_webhook,
      type_id: webhookData.type_id || null,
      feature_ids: null,
      search_mode: 'multi',
      pre_parsed: true
    }
  };
}

// ============================================
// CHECK FOR PRE-PARSED DATA (from ChatBot smart parsing)
// ============================================

if (webhookData.pre_parsed === true) {
  // Data already validated and IDs resolved by ChatBot
  // Skip redundant validation for better performance

  const LOCATION_MAP = (typeof mapsData.location_map === 'object') ? (mapsData.location_map || {}) : JSON.parse(mapsData.location_map || '{}');
  const TYPE_MAP = (typeof mapsData.type_map === 'object') ? (mapsData.type_map || {}) : JSON.parse(mapsData.type_map || '{}');
  const FEATURE_MAP = (typeof mapsData.feature_map === 'object') ? (mapsData.feature_map || {}) : JSON.parse(mapsData.feature_map || '{}');

  // Handle multi-location mode
  const search_mode = webhookData.search_mode || 'single';
  const location_ids = webhookData.location_ids || [];

  return {
    json: {
      skip_search: false,
      location_id: webhookData.location_id,
      location_ids: location_ids,
      type_id: webhookData.type_id,
      feature_ids: null, // Will be resolved below if needed
      search_mode: search_mode,
      LOCATION_MAP,
      TYPE_MAP,
      FEATURE_MAP,
      pre_parsed: true
    }
  };
}

// ============================================
// STANDARD VALIDATION (backwards compatible)
// ============================================

const LOCATION_MAP = (typeof mapsData.location_map === 'object') ? (mapsData.location_map || {}) : JSON.parse(mapsData.location_map || '{}');
const TYPE_MAP = (typeof mapsData.type_map === 'object') ? (mapsData.type_map || {}) : JSON.parse(mapsData.type_map || '{}');
const FEATURE_MAP = (typeof mapsData.feature_map === 'object') ? (mapsData.feature_map || {}) : JSON.parse(mapsData.feature_map || '{}');

function normalize(str) {
  if (!str) return '';
  return str.toString().toLowerCase().trim();
}

function findId(name, map) {
  if (!name) return null;
  const norm = normalize(name);
  // Remove trailing 's' for plural handling
  const normSingular = norm.replace(/s$/, '');

  for (const [key, value] of Object.entries(map)) {
    const keyNorm = normalize(key);
    const keySingular = keyNorm.replace(/s$/, '');

    // Exact match
    if (keyNorm === norm) return value;
    // Singular match
    if (keySingular === normSingular) return value;
    // Contains match (for compound types)
    if (keyNorm.includes(norm) || norm.includes(keyNorm)) return value;
  }
  return null;
}

function getAvailableOptions(map, limit = 15) {
  const keys = Object.keys(map);
  if (keys.length === 0) return 'none available';
  if (keys.length <= limit) return keys.join(', ');
  return keys.slice(0, limit).join(', ') + ` and ${keys.length - limit} more`;
}

let skip_search = false;
let errorMessage = '';

const hasLocation = mergedData.location_name && mergedData.location_name.trim() !== '';
const hasType = mergedData.property_type && mergedData.property_type.trim() !== '';

// Validation rules
if (!hasLocation && !hasType) {
  skip_search = true;
  errorMessage = `Please tell me what you're looking for!\n\nI need both:\n📍 **Location** (e.g., Marbella, Estepona)\n🏠 **Property type** (e.g., villa, apartment)\n\nFor example: "3 bedroom villas in Marbella"`;
  return { json: { skip_search: true, result: errorMessage } };
}

if (!hasLocation && hasType) {
  skip_search = true;
  errorMessage = `Which location are you interested in?\n\n**Available locations:**\n${getAvailableOptions(LOCATION_MAP, 20)}`;
  return { json: { skip_search: true, result: errorMessage } };
}

if (hasLocation && !hasType) {
  skip_search = true;
  errorMessage = `What type of property are you looking for?\n\n**Available types:**\n${getAvailableOptions(TYPE_MAP, 10)}`;
  return { json: { skip_search: true, result: errorMessage } };
}

const location_id = findId(mergedData.location_name, LOCATION_MAP);
const type_id = findId(mergedData.property_type, TYPE_MAP);

if (!location_id && !type_id) {
  return { json: { skip_search: true, result: `I couldn't find matches for both location and property type.\n\n**Available locations:** ${getAvailableOptions(LOCATION_MAP, 15)}\n\n**Available types:** ${getAvailableOptions(TYPE_MAP, 10)}` } };
}

if (!location_id) {
  return { json: { skip_search: true, result: `I couldn't find properties in "${mergedData.location_name}".\n\n**Available locations:**\n${getAvailableOptions(LOCATION_MAP, 20)}` } };
}

if (!type_id) {
  return { json: { skip_search: true, result: `I couldn't find "${mergedData.property_type}" in our property types.\n\n**Available types:**\n${getAvailableOptions(TYPE_MAP, 10)}` } };
}

// Find feature IDs
let feature_ids = null;
if (mergedData.features) {
  const featureNames = mergedData.features.split(',').map(f => f.trim()).filter(Boolean);
  const ids = featureNames.map(fname => findId(fname, FEATURE_MAP)).filter(Boolean);
  if (ids.length > 0) feature_ids = ids.join(',');
}

return { json: { skip_search: false, location_id, type_id, feature_ids, search_mode: 'single', location_ids: [], LOCATION_MAP, TYPE_MAP, FEATURE_MAP } };

// ============================================
// BUILD API QUERY PARAMETERS
// Supports single, multi-location, and ref_no searches
// ============================================

const mergedData = $('Merge Request with Context').first().json;
const lookup = $('Validate & Lookup IDs').first().json;

const params = {
  page: parseInt(mergedData.page) || 1,
  limit: parseInt(mergedData.limit) || 20,
  ln: mergedData.language || 'en_US',
};

// Multi-location support
const search_mode = lookup.search_mode || 'single';
const location_ids = lookup.location_ids || [];

// Reference number search (from lookup or mergedData)
const refNo = lookup.ref_no || mergedData.ref_no || '';
if (refNo.trim()) params.ref_no = refNo.trim();

// Handle single vs multi-location
if (search_mode === 'multi' && location_ids.length > 0) {
  params.location_ids = location_ids;
  params.search_mode = 'multi';
} else if (lookup.location_id) {
  params.location_id = lookup.location_id;
  params.search_mode = 'single';
}

if (lookup.type_id) params.type_id = lookup.type_id;
if (mergedData.listing_type?.trim()) params.listing_type = mergedData.listing_type.trim();

if (parseInt(mergedData.bedrooms_min) > 0) params.bedrooms_min = parseInt(mergedData.bedrooms_min);
if (parseInt(mergedData.bedrooms_max) > 0) params.bedrooms_max = parseInt(mergedData.bedrooms_max);
if (parseInt(mergedData.bathrooms_min) > 0) params.bathrooms_min = parseInt(mergedData.bathrooms_min);
if (parseInt(mergedData.bathrooms_max) > 0) params.bathrooms_max = parseInt(mergedData.bathrooms_max);
if (parseInt(mergedData.list_price_min) > 0) params.list_price_min = parseInt(mergedData.list_price_min);
if (parseInt(mergedData.list_price_max) > 0) params.list_price_max = parseInt(mergedData.list_price_max);
if (parseInt(mergedData.build_size_min) > 0) params.build_size_min = parseInt(mergedData.build_size_min);
if (parseInt(mergedData.build_size_max) > 0) params.build_size_max = parseInt(mergedData.build_size_max);
if (parseInt(mergedData.plot_size_min) > 0) params.plot_size_min = parseInt(mergedData.plot_size_min);
if (parseInt(mergedData.plot_size_max) > 0) params.plot_size_max = parseInt(mergedData.plot_size_max);

if (lookup.feature_ids?.trim()) params.features = lookup.feature_ids.trim();
params.order = mergedData.order || 'last_date_desc';

return { json: params };

// ============================================
// FETCH PROPERTIES - SUPPORTS MULTI-LOCATION
// ============================================

const params = $input.first().json;
const mapsData = $('Load Client Maps').first().json;
const apiBaseUrl = mapsData.prop_api_base_url || '';
const authHeader = mapsData.prop_auth_header || '';

// Build query string from params
function buildQueryString(baseParams, locationId) {
  const parts = [];

  parts.push('page=' + (baseParams.page || 1));
  parts.push('limit=' + (baseParams.limit || 20));
  parts.push('ln=' + encodeURIComponent(baseParams.ln || 'en_US'));

  if (locationId) parts.push('location_id=' + locationId);
  if (baseParams.type_id) parts.push('type_id=' + baseParams.type_id);
  if (baseParams.ref_no) parts.push('ref_no=' + encodeURIComponent(baseParams.ref_no));
  if (baseParams.listing_type) parts.push('listing_type=' + encodeURIComponent(baseParams.listing_type));
  if (baseParams.bedrooms_min) parts.push('bedrooms_min=' + baseParams.bedrooms_min);
  if (baseParams.bedrooms_max) parts.push('bedrooms_max=' + baseParams.bedrooms_max);
  if (baseParams.bathrooms_min) parts.push('bathrooms_min=' + baseParams.bathrooms_min);
  if (baseParams.bathrooms_max) parts.push('bathrooms_max=' + baseParams.bathrooms_max);
  if (baseParams.list_price_min) parts.push('list_price_min=' + baseParams.list_price_min);
  if (baseParams.list_price_max) parts.push('list_price_max=' + baseParams.list_price_max);
  if (baseParams.build_size_min) parts.push('build_size_min=' + baseParams.build_size_min);
  if (baseParams.build_size_max) parts.push('build_size_max=' + baseParams.build_size_max);
  if (baseParams.plot_size_min) parts.push('plot_size_min=' + baseParams.plot_size_min);
  if (baseParams.plot_size_max) parts.push('plot_size_max=' + baseParams.plot_size_max);
  if (baseParams.features) parts.push('features=' + encodeURIComponent(baseParams.features));
  if (baseParams.order) parts.push('order=' + encodeURIComponent(baseParams.order));

  return parts.join('&');
}

// Determine search mode
const searchMode = params.search_mode || 'single';
const locationIds = params.location_ids || [];

// For multi-location, we'll do sequential requests
if (searchMode === 'multi' && locationIds.length > 0) {
  // Store properties grouped by location
  const propertiesByLocation = {};
  let totalCount = 0;
  const seenRefs = new Set();

  for (const locId of locationIds) {
    propertiesByLocation[locId] = [];
    const queryString = buildQueryString(params, locId);
    const url = apiBaseUrl + 'v1/property?' + queryString;

    try {
      const response = await this.helpers.httpRequest({
        method: 'GET',
        url: url,
        headers: { 'access_token': authHeader },
        json: true
      });

      totalCount += (response.count || 0);
      const properties = response.data || [];
      for (const prop of properties) {
        const ref = prop.ref_no || prop.id;
        if (!seenRefs.has(ref)) {
          seenRefs.add(ref);
          // Tag the property with the search location ID
          prop._search_location_id = locId;
          propertiesByLocation[locId].push(prop);
        }
      }
    } catch (e) {
      // Continue with other locations if one fails
    }
  }

  // Combine all properties (keeping location order)
  const allProperties = [];
  for (const locId of locationIds) {
    allProperties.push(...(propertiesByLocation[locId] || []));
  }

  return {
    json: {
      data: allProperties,
      count: allProperties.length,
      total_from_apis: totalCount,
      search_mode: 'multi',
      locations_searched: locationIds.length,
      properties_by_location: propertiesByLocation
    }
  };
} else {
  // Single location: standard request
  const queryString = buildQueryString(params, params.location_id);
  const url = apiBaseUrl + 'v1/property?' + queryString;

  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    headers: { 'access_token': authHeader },
    json: true
  });

  return { json: response };
}

// Format property results - supports multi-location with grouped display
const response = $input.item.json;
const properties = response.data || [];
const mergedData = $('Merge Request with Context').first().json;
const webhookData = $('Property Search Webhook').first().json.body || {};

// Check if this is a multi-location search
const searchMode = response.search_mode || 'single';
const locationNames = webhookData.location_names || [];
const locationIds = webhookData.location_ids || [];

if (properties.length === 0) {
  let filters = [];
  if (mergedData.property_type) filters.push(`**Type:** ${mergedData.property_type}`);
  if (mergedData.location_name) filters.push(`**Location:** ${mergedData.location_name}`);
  if (locationNames.length > 1) filters.push(`**Locations:** ${locationNames.join(', ')}`);
  if (mergedData.bedrooms_min > 0) filters.push(`**Bedrooms:** ${mergedData.bedrooms_min}+`);
  if (mergedData.list_price_min > 0 && mergedData.list_price_max > 0) {
    filters.push(`**Price:** €${mergedData.list_price_min.toLocaleString()} - €${mergedData.list_price_max.toLocaleString()}`);
  } else if (mergedData.list_price_min > 0) {
    filters.push(`**Price:** Above €${mergedData.list_price_min.toLocaleString()}`);
  } else if (mergedData.list_price_max > 0) {
    filters.push(`**Price:** Under €${mergedData.list_price_max.toLocaleString()}`);
  }
  if (mergedData.bathrooms_min > 0) filters.push(`**Bathrooms:** ${mergedData.bathrooms_min}+`);

  let noResultsMsg = `I couldn't find any properties matching your search criteria.`;
  if (filters.length > 0) {
    noResultsMsg += `\n\n**Applied filters:**\n${filters.join('\n')}`;
    noResultsMsg += `\n\nTry adjusting your filters - for example, increase your budget or try a different location.\n\n💡 Type **"reset"** to clear all filters and start a fresh search.`;
  }

  return {
    json: {
      result: noResultsMsg,
      should_save_context: false,
      session_id: mergedData.session_id,
      location_name: mergedData.location_name,
      property_type: mergedData.property_type,
      list_price_min: mergedData.list_price_min,
      list_price_max: mergedData.list_price_max,
      bedrooms_min: mergedData.bedrooms_min,
      bedrooms_max: mergedData.bedrooms_max,
      bathrooms_min: mergedData.bathrooms_min,
      bathrooms_max: mergedData.bathrooms_max,
      features: mergedData.features
    }
  };
}

// Helper function to format a single property
function formatProperty(p, index) {
  const name = p.name || 'Property';
  const locationName = p.location_id?.name || p.location_name || p.city || 'Unknown';
  const beds = p.bedrooms || 0;
  const baths = p.bathrooms || 0;
  const buildSize = p.build_size || p.build_area || 0;
  const plotSize = p.plot_size || p.plot_area || 0;
  const price = p.list_price || 0;
  const ref = p.ref_no || '';
  const url = mergedData.PROP_DETAIL_URL ? `${mergedData.PROP_DETAIL_URL}${ref}` : '';

  const sizeLine = buildSize || plotSize
    ? `📐 ${buildSize ? buildSize + ' m² build' : ''}${buildSize && plotSize ? ' | ' : ''}${plotSize ? plotSize + ' m² plot' : ''}\n`
    : '';

  return `**${name}**\n🛏️ ${beds} beds | 🚿 ${baths} baths\n${sizeLine}🔑 Ref: ${ref}\n💰 €${price.toLocaleString()}\n🔗 [View Property](${url})`;
}

const total = response.count || properties.length;
let message = '';

// Multi-location: group properties by location and show 3 from each
if (searchMode === 'multi' && locationIds.length > 1) {
  // Build a map of location_id to location_name
  const locIdToName = {};
  for (let i = 0; i < locationIds.length; i++) {
    locIdToName[locationIds[i]] = locationNames[i] || `Location ${locationIds[i]}`;
  }

  // Use pre-grouped data from Fetch Properties if available
  const propertiesByLocation = response.properties_by_location || {};

  // If not available, group by _search_location_id tag
  const grouped = {};
  if (Object.keys(propertiesByLocation).length > 0) {
    for (const locId of locationIds) {
      grouped[locId] = propertiesByLocation[locId] || [];
    }
  } else {
    // Fallback: group by _search_location_id
    for (const locId of locationIds) {
      grouped[locId] = [];
    }
    for (const prop of properties) {
      const searchLocId = prop._search_location_id;
      if (searchLocId && grouped[searchLocId]) {
        grouped[searchLocId].push(prop);
      }
    }
  }

  const maxPerLocation = 3;
  const locationSections = [];

  for (const locId of locationIds) {
    const locName = locIdToName[locId] || 'Unknown';
    const locProps = grouped[locId] || [];

    if (locProps.length > 0) {
      const items = locProps.slice(0, maxPerLocation);
      const propList = items.map((p, i) => formatProperty(p, i)).join('\n\n');
      locationSections.push(`**${locName.charAt(0).toUpperCase() + locName.slice(1)}**\n${propList}`);
    } else {
      locationSections.push(`**${locName.charAt(0).toUpperCase() + locName.slice(1)}**\nNo properties found in this location.`);
    }
  }

  const locNamesDisplay = locationNames.map(n => n.charAt(0).toUpperCase() + n.slice(1)).join(' and ');
  message = `Here are some ${mergedData.property_type || 'properties'} in ${locNamesDisplay}:\n\n`;
  message += locationSections.join('\n\n');
  message += `\n\nLet me know if you'd like to see more options or refine your search!`;
} else {
  // Single location: original behavior
  const maxToShow = 3;
  const items = properties.slice(0, maxToShow);
  const propertyList = items.map((p, i) => formatProperty(p, i)).join('\n\n');

  message = `I found ${total} properties matching your criteria`;
  if (mergedData.property_type) message += ` for ${mergedData.property_type}`;
  if (mergedData.location_name) message += ` in ${mergedData.location_name}`;
  message += `. Here are the top ${items.length} featured properties:\n\n`;
  message += propertyList;
  if (total > maxToShow) {
    message += `\n\nShowing ${maxToShow} of ${total} properties. Let me know if you'd like to see more or refine your search!`;
  }
}

message += `\n\n💡 _Tip: Type **"reset"** anytime to clear filters and start fresh._`;

return {
  json: {
    result: message,
    should_save_context: true,
    session_id: mergedData.session_id,
    location_name: mergedData.location_name,
    property_type: mergedData.property_type,
    list_price_min: mergedData.list_price_min,
    list_price_max: mergedData.list_price_max,
    bedrooms_min: mergedData.bedrooms_min,
    bedrooms_max: mergedData.bedrooms_max,
    bathrooms_min: mergedData.bathrooms_min,
    bathrooms_max: mergedData.bathrooms_max,
    features: mergedData.features
  }
};

// Prepare final response
let formatValidationError = null;
let formatEnhancedResults = null;

try { formatValidationError = $('Format Validation Error').first()?.json; } catch (e) {}
try { formatEnhancedResults = $('Format Results').first()?.json; } catch (e) {}

if (formatValidationError && formatValidationError.result) {
  return { json: { result: formatValidationError.result } };
} else if (formatEnhancedResults && formatEnhancedResults.result) {
  return { json: { result: formatEnhancedResults.result } };
} else {
  return { json: { result: "An error occurred processing your request. Please try again." } };
}

// Extract unique features from properties
const response = $input.item.json;
const properties = response.data || [];
const featureMap = new Map();

for (const property of properties) {
  const features = property.features || property.property_features || property.amenities || [];
  if (Array.isArray(features)) {
    for (const feature of features) {
      if (typeof feature === 'object' && feature !== null) {
        const id = feature.id || feature.feature_id;
        const name = feature.name || feature.feature_name || feature.title;
        if (id && name && !featureMap.has(String(name).trim())) {
          featureMap.set(String(name).trim(), parseInt(id));
        }
      }
    }
  }
}

return { json: { data: Array.from(featureMap.entries()).map(([name, id]) => ({ id, name })), count: featureMap.size } };

// Build location, type, and feature maps
const locationsData = $('Fetch Locations').first().json;
const typesData = $('Fetch Property Types').first().json;
const featuresData = $('Extract Features').first().json;
const clientId = $('Set Client Context').first().json.client_id;

const locations = locationsData.data || locationsData.locations || (Array.isArray(locationsData) ? locationsData : []);
const types = typesData.data || typesData.types || (Array.isArray(typesData) ? typesData : []);
const features = featuresData.data || featuresData.features || (Array.isArray(featuresData) ? featuresData : []);

// Build location map
const locationMap = {};
for (const loc of locations) {
  const name = (loc.name || loc.location_name || '').toLowerCase().trim();
  const id = loc.id || loc.location_id;
  if (name && id) {
    locationMap[name] = parseInt(id);
    const cleanName = name.replace(/[^a-z0-9]/g, '');
    if (cleanName !== name) locationMap[cleanName] = parseInt(id);
  }
}

// Build type map (sorted by ID, lowest first)
const typeMap = {};
const sortedTypes = types.filter(t => t.name && t.id).sort((a, b) => parseInt(a.id) - parseInt(b.id));
for (const type of sortedTypes) {
  const name = (type.name || type.type_name || '').toLowerCase().trim();
  const id = type.id || type.type_id;
  if (name && id) {
    if (!typeMap[name]) typeMap[name] = parseInt(id);
    if (!name.endsWith('s') && !typeMap[name + 's']) typeMap[name + 's'] = parseInt(id);
    if (name.endsWith('s') && !typeMap[name.slice(0, -1)]) typeMap[name.slice(0, -1)] = parseInt(id);
  }
}

// Build feature map
const featureMap = {};
for (const feature of features) {
  const name = (feature.name || feature.feature_name || '').toLowerCase().trim();
  const id = feature.id || feature.feature_id;
  if (name && id) {
    featureMap[name] = parseInt(id);
    const cleanName = name.replace(/[^a-z0-9]/g, '');
    if (cleanName !== name) featureMap[cleanName] = parseInt(id);
    const underscoredName = name.replace(/\s+/g, '_');
    if (underscoredName !== name) featureMap[underscoredName] = parseInt(id);
  }
}

return {
  json: {
    client_id: clientId,
    location_map: locationMap,
    type_map: typeMap,
    feature_map: featureMap,
    location_count: Object.keys(locationMap).length,
    type_count: Object.keys(typeMap).length,
    feature_count: Object.keys(featureMap).length,
    updated_at: new Date().toISOString()
  }
};

const data = $input.first().json;

const locationMapJson = JSON.stringify(data.location_map).replace(/'/g, "''");
const typeMapJson = JSON.stringify(data.type_map).replace(/'/g, "''");
const featureMapJson = JSON.stringify(data.feature_map).replace(/'/g, "''");

const sql = `
UPDATE client_variables
SET variables = jsonb_set(
  jsonb_set(
    jsonb_set(variables, '{LOCATION_MAP}', '${locationMapJson}'::jsonb),
    '{TYPE_MAP}', '${typeMapJson}'::jsonb
  ),
  '{FEATURE_MAP}', '${featureMapJson}'::jsonb
)
WHERE client_id = '${data.client_id}';

UPDATE client_variables
SET variables = jsonb_set(variables, '{CACHE_UPDATED_AT}', '"${data.updated_at}"'::jsonb)
WHERE client_id = '${data.client_id}';

SELECT '${data.client_id}' as client_id, ${data.location_count} as locations_cached,
  ${data.type_count} as types_cached, ${data.feature_count} as features_cached, '${data.updated_at}' as cached_at;
`;

return { json: { sql, client_id: data.client_id, location_count: data.location_count, type_count: data.type_count, feature_count: data.feature_count, updated_at: data.updated_at } };

const allResults = $input.all();
const summary = {
  total_clients: allResults.length,
  successful_updates: allResults.filter(r => r.json.client_id).length,
  timestamp: new Date().toISOString(),
  details: allResults.map(r => ({ client_id: r.json.client_id, locations_cached: r.json.locations_cached, types_cached: r.json.types_cached, features_cached: r.json.features_cached }))
};
console.log('=== CACHE UPDATE SUMMARY ===');
console.log(`Total clients: ${summary.total_clients}, Successful: ${summary.successful_updates}`);
return { json: summary };
